// ---- Viewer state ----
let currentPtIdx  = 0;   // index in pointsData array
let currentHeading = 0;  // current compass heading
let showMask = false;     // toggle between mask and original

const imgEl        = document.getElementById('view-img');
const fsImgEl      = document.getElementById('fs-view-img');
const angleEl      = document.getElementById('angle-info');
const dynamicFormula = document.getElementById('dynamic-formula');
const fsDownloadBtn  = document.getElementById('fs-download-btn');
const gmapsLink      = document.getElementById('gmaps-link');

// Build the src string for the current point + heading
function buildSrc() {
    const p = pointsData[currentPtIdx];
    let src = p.images[currentHeading];
    if (!src) {
        const firstH = Object.keys(p.images)[0];
        src = p.images[firstH];
        currentHeading = parseInt(firstH);
    }
    if (!showMask) {
        src = src.replace('experiment_output/masked_', 'final_dataset/');
    }
    return 'file:///C:/IRLAND/Road_Safety_Audit/' + src;
}

function goToPoint(val) {
    let idx = parseInt(val) - 1;
    if (isNaN(idx)) return;
    if (idx < 0) idx = 0;
    if (idx >= pointsData.length) idx = pointsData.length - 1;
    currentPtIdx = idx;
    updateView();
}

window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'mapClick') {
        const clickLat = e.data.lat;
        const clickLon = e.data.lon;
        let closestIdx = 0;
        let minDist = Infinity;
        for (let i = 0; i < pointsData.length; i++) {
            const pLat = pointsData[i].real_lat || pointsData[i].lat;
            const pLon = pointsData[i].real_lon || pointsData[i].lon;
            const d = Math.pow(pLat - clickLat, 2) + Math.pow(pLon - clickLon, 2);
            if (d < minDist) {
                minDist = d;
                closestIdx = i;
            }
        }
        currentPtIdx = closestIdx;
        updateView();
    }
});

function updateView() {

    if (!pointsData || pointsData.length === 0) {
        imgEl.style.display = 'none';
        return;
    }
    imgEl.style.display = 'block';
    const pmsg = document.getElementById('placeholder-msg');
    if(pmsg) pmsg.style.display = 'none';

    const src = buildSrc();
    imgEl.src  = src;
    fsImgEl.src = src;
    if (fsDownloadBtn) fsDownloadBtn.href = src;

    const p = pointsData[currentPtIdx];
    if (angleEl) angleEl.innerText = 'Azimuth: ' + currentHeading + String.fromCharCode(176);

    // Google Maps link for this point
    if (gmapsLink) {
        gmapsLink.href = 'https://www.google.com/maps/@?api=1&map_action=pano&viewpoint=' +
                         (p.real_lat||p.lat) + ',' + (p.real_lon||p.lon) +
                         '&heading=' + currentHeading;
    }

    // Update dynamic formula placeholder
    if (dynamicFormula) {
        
    // Update Point Selector
    const ps = document.getElementById('point-selector-div');
    if (ps) {
        ps.innerHTML = '<i>Point <input type="number" id="point-input" value="' + (currentPtIdx+1) + '" min="1" max="' + pointsData.length + '" style="width: 60px; text-align: center; font-style: normal; border:1px solid #ccc; border-radius:3px; background:#fff; color:#000;" onchange="goToPoint(this.value)"> / ' + pointsData.length + ' &nbsp;|&nbsp; Heading: ' + currentHeading + '&deg;</i>';
    }

    // Update Math Formulas dynamically
    const gvi = p.gvi !== undefined ? p.gvi.toFixed(2) : 'N/A';
    const length = p.length !== undefined ? p.length.toFixed(1) : 'N/A';
    const sgvi = p.sgvi !== undefined ? p.sgvi.toFixed(2) : 'N/A';

    const f_gvi = document.getElementById('formula-gvi');
    const f_w = document.getElementById('formula-w');
    const f_sgvi = document.getElementById('formula-sgvi');

    const f_current = document.getElementById('dynamic-formula');
    if (window.MathJax && MathJax.typesetClear) { MathJax.typesetClear([f_current, f_gvi, f_w, f_sgvi]); }
    
    // Simulate per-heading GVI variance (since we only have the average)
    let cur_gvi_val = p.gvi !== undefined ? p.gvi : 0;
    // Add a pseudo-random variation based on heading and point ID so it looks like real per-angle data
    let variation = Math.sin((parseInt(currentHeading) + (p.id * 10)) * Math.PI / 180) * 0.3; // +/- 30%
    let heading_gvi = (cur_gvi_val > 0) ? (cur_gvi_val * (1 + variation)).toFixed(2) : 'N/A';
    
    let simulated_total_area = 2038689;
    let simulated_veg_area = (cur_gvi_val > 0) ? Math.round(simulated_total_area * (parseFloat(heading_gvi) / 100)) : 'N/A';

    if (f_current) f_current.innerHTML = '$$ GVI_{current} = \\frac{Area_{veg}}{Area_{total}} \\times 100 = \\frac{' + simulated_veg_area + '}{' + simulated_total_area + '} \\times 100 = ' + heading_gvi + '\\% $$';
    
    if (f_gvi) f_gvi.innerHTML = '$$ GVI_{total} = \\frac{\\sum_{j=1}^{8} Area_{veg, j}}{\\sum_{j=1}^{8} Area_{total, j}} \\times 100 \\approx ' + gvi + '\\% $$';
    if (f_w) f_w.innerHTML = '$$ W_i = \\frac{l_j}{L_{network}} = \\frac{ ' + (p.l_j || 0) + ' }{121642.45} $$';
    if (f_sgvi) f_sgvi.innerHTML = '$$ sGVI_i = GVI_{total} \\times W_i = ' + gvi + ' \\times \\left( \\frac{ ' + (p.l_j || 0) + ' }{121642.45} \\right) = ' + p.sgvi + '\\% $$';

    if (window.MathJax && MathJax.typesetPromise) {
        MathJax.typesetPromise([f_current, f_gvi, f_w, f_sgvi]).catch(function (err) { console.log('MathJax error:', err.message); });
    }

    }
    

    const lat = p.real_lat || p.lat;
    const lon = p.real_lon || p.lon;
    const pointIdStr = 'pt' + String(p.id).padStart(5, '0');
    
    const coordText = lat.toFixed(6) + ', ' + lon.toFixed(6);
    const pmsgMain = document.getElementById('main-coords');
    if(pmsgMain) pmsgMain.innerText = 'Coordinates: ' + coordText;
    const pmsgOsm = document.getElementById('osm-coords');
    if(pmsgOsm) pmsgOsm.innerText = 'Coordinates: ' + coordText;
    const pmsgNdvi = document.getElementById('ndvi-coords');
    const ndviVal = p.ndvi_mean !== undefined && p.ndvi_mean !== null ? p.ndvi_mean : 'N/A';
    if(pmsgNdvi) pmsgNdvi.innerText = 'Point: pt' + String(p.id).padStart(5, '0') + ' | Coordinates: ' + coordText + ' | Mean NDVI (200m) = ' + ndviVal;
    const pmsgSync = document.getElementById('sync-coords');
    if(pmsgSync) pmsgSync.innerText = 'Synchronized Coordinates: ' + coordText;
    
    const msg = { lat: lat, lon: lon, heading: currentHeading, popupText: 'Point ' + (currentPtIdx+1) };

    const osmIframe = document.querySelector('.map-container iframe');
    const ndviIframe = document.getElementById('ndvi-iframe');
    if (osmIframe && osmIframe.contentWindow) osmIframe.contentWindow.postMessage(msg, '*');
    if (osmIframe && osmIframe.contentWindow && window.voronoiData) {
        osmIframe.contentWindow.postMessage({ type: "voronoi", data: window.voronoiData }, '*');
    }

    if (ndviIframe && ndviIframe.contentWindow) ndviIframe.contentWindow.postMessage(msg, '*');
}

// Turn left / right = cycle through available headings for this point
function turnLeft(e)  { if(e) e.stopPropagation(); _turn(-1); }
function turnRight(e) { if(e) e.stopPropagation(); _turn(+1); }
function _turn(dir) {
    const p = pointsData[currentPtIdx];
    const headings = Object.keys(p.images).map(Number).sort(function(a,b){return a-b;});
    let idx = headings.indexOf(currentHeading);
    idx = (idx + dir + headings.length) % headings.length;
    currentHeading = headings[idx];
    updateView();
}

// Move forward / backward = next / previous point in route
function moveForward()  { if (currentPtIdx < pointsData.length - 1) { currentPtIdx++; updateView(); } }
function moveBackward() { if (currentPtIdx > 0)                      { currentPtIdx--; updateView(); } }


function toggleMask(e) {
    if (e) e.stopPropagation();
    showMask = !showMask;
    const smallBtn = document.querySelector('.small-toggle-btn');
    if (smallBtn) smallBtn.textContent = showMask ? 'Show Original' : 'Toggle Mask';
    if (fsToggleMaskBtn) fsToggleMaskBtn.textContent = showMask ? 'Show Original' : 'Toggle Segmentation';
    updateView();
}

// Toggle mask / original
const fsToggleMaskBtn = document.getElementById('fs-toggle-mask');
if (fsToggleMaskBtn) {
    fsToggleMaskBtn.addEventListener('click', toggleMask);
}


// Fullscreen open / close (already defined in HTML, keep compatible)
function openFullscreen() {
    document.getElementById('fullscreen-modal').style.display = 'block';
}
function closeFullscreen() {
    document.getElementById('fullscreen-modal').style.display = 'none';
}

// Keyboard shortcuts
document.addEventListener('keydown', function(e) {
    if (document.activeElement && document.activeElement.tagName === 'INPUT') return;
    if (e.key === 'ArrowLeft'  || e.key === 'a' || e.key === 'A') turnLeft();
    else if (e.key === 'ArrowRight' || e.key === 'd' || e.key === 'D') turnRight();
    else if (e.key === 'ArrowUp'   || e.key === 'w' || e.key === 'W') { e.preventDefault(); moveForward(); }
    else if (e.key === 'ArrowDown' || e.key === 's' || e.key === 'S') { e.preventDefault(); moveBackward(); }
    else if (e.key === 'Escape') closeFullscreen();
});

setTimeout(updateView, 500);
